module priority_encoder_4to2 (obf_a, y);
   input [3:0] obf_a;
   output reg [1:0] y;

   always @(obf_a) begin
      if (obf_a[3])
         y = 2'b11;
      else if (obf_a[2])
         y = 2'b10;
      else if (obf_a[1])
         y = 2'b01;
      else if (obf_a[0])
         y = 2'b00;
      else
         y = 2'b00; // Default case if no input is set
   end
endmodule
